[DataContractAttribute]
public class ETG_CustOpeningBalanceContract implements SysOperationValidatable
{
    TransDate    AsOnDate;
    TransDate    toDate;
    CustAccount  customerAccount;

}

Method.Source:
[
    DataMemberAttribute('AsOnDate'),
    SysOperationLabelAttribute(literalStr("As On Date")),
    SysOperationHelpTextAttribute(literalStr("Enter the from date for opening balance"))
]
public TransDate parmAsOnDate(TransDate _asonDate = asonDate)
{
    asonDate = _asonDate;
    return asonDate;
}

[
    DataMemberAttribute('CustomerAccount'),
    SysOperationLabelAttribute(literalStr("Customer Account")),
    SysOperationHelpTextAttribute(literalStr("Select the customer account"))
]
public CustAccount parmCustomerAccount(CustAccount _customerAccount = customerAccount)
{
    customerAccount = _customerAccount;
    return customerAccount;
}

public boolean validate()
{


    boolean isValid = true;

    if (!asonDate)
    {
        isValid = checkFailed("As On Date is required.");
    }

    // Validation logic: As On Date must be today or earlier
    if (asonDate > today())
    {
        isValid = checkFailed("As On date cannot be greater than today date.");
    }

    return isValid;
}
